const leaseControlOperations = `-- name: LeaseControlOperations :many
UPDATE control_operations
SET state = 'running', attempts = attempts + 1, next_attempt_at = NULL,
    lease_expires_at = $1, updated_at = $2
WHERE id IN (
  SELECT id FROM control_operations
  WHERE (state IN ('pending','failed','uncertain') AND (next_attempt_at IS NULL OR next_attempt_at <= $2))
     OR (state = 'running' AND lease_expires_at <= $2)
  ORDER BY coalesce(next_attempt_at, created_at), created_at
  FOR UPDATE SKIP LOCKED
  LIMIT $3
)
RETURNING id, operation_key, operation_type, request_hash, state, result, last_error, attempts, next_attempt_at, lease_expires_at, uncertain_at, completed_at, created_at, updated_at
`

type LeaseControlOperationsParams struct {
	LeaseExpiresAt sql.NullTime
	Now            time.Time
	BatchSize      int32
}

func (q *Queries) LeaseControlOperations(ctx context.Context, arg LeaseControlOperationsParams) ([]ControlOperation, error) {
	rows, err := q.db.QueryContext(ctx, leaseControlOperations, arg.LeaseExpiresAt, arg.Now, arg.BatchSize)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []ControlOperation
	for rows.Next() {
		var i ControlOperation
		if err := rows.Scan(
			&i.ID,
			&i.OperationKey,
			&i.OperationType,
			&i.RequestHash,
			&i.State,
			&i.Result,
			&i.LastError,
			&i.Attempts,
			&i.NextAttemptAt,
			&i.LeaseExpiresAt,
			&i.UncertainAt,
			&i.CompletedAt,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

